"use strict";parserFactory.register("asianovel.net",()=>new AsianovelParser);class AsianovelParser extends Parser{constructor(){super()}async getChapterUrls(e){return[...e.querySelectorAll(".chapter-group__list a")].map(e=>util.hyperLinkToChapter(e))}findContent(e){return e.querySelector("#chapter-content")}extractTitleImpl(e){return e.querySelector(".story__identity-title")}findChapterTitle(e){return e.querySelector(".chapter__title")}findCoverImageUrl(e){return util.getFirstImgSrc(e,"article")}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll(".story__summary")]}}